#import "AppDelegate.h"
#import "EmulatorViewController.h"
#include "../gs/GSH_OpenGL/GSH_OpenGL.h"
#include "DebuggerSimulator.h"
// AYS2 overlay (seam): replaces the storyboard-provided root view controller
// with a SwiftUI shell. Play-Swift.h is generated by Xcode from
// AYS2RootView.swift (this target already declares "LANGUAGES C Swift").
#import "Play-Swift.h"

@interface AppDelegate ()

@end

@implementation AppDelegate

- (BOOL)application:(UIApplication*)application didFinishLaunchingWithOptions:(NSDictionary*)launchOption
{
	[EmulatorViewController registerPreferences];
	CGSH_OpenGL::RegisterPreferences();

	// AYS2 overlay (seam): Main.storyboard already set self.window and its
	// initial rootViewController by this point (no Scene support in this
	// app, so UIApplicationMain does that from Info.plist's
	// UIMainStoryboardFile before this method runs) — swap it for our
	// SwiftUI shell instead of touching the storyboard XML itself.
	self.window.rootViewController = [AYS2RootViewFactory makeRootViewController];

	return YES;
}

- (void)applicationWillResignActive:(UIApplication*)application
{
}

- (void)applicationDidEnterBackground:(UIApplication*)application
{
}

- (void)applicationWillEnterForeground:(UIApplication*)application
{
}

- (void)applicationDidBecomeActive:(UIApplication*)application
{
}

- (void)applicationWillTerminate:(UIApplication*)application
{
	StopSimulateDebugger();
}

@end
